// Superclass
class Hewan {
 String nama;

 void makan() {
 System.out.println(nama + " sedang makan");
 }
}

// Subclass mewarisi Hewan
class Kucing extends Hewan {

 void bersuara() {
 System.out.println(nama + " berkata: Meow!");
 }
}

public class Main {
 public static void main(String[] args) {
 Kucing k = new Kucing();
 k.nama = "Kitty";
 k.makan(); // Dari superclass
 k.bersuara(); // Dari subclass
 }
}

public class ContohArray {
 public static void main(String[] args) {

 // Deklarasi array dengan 5 elemen
 int[] angka = {10, 20, 30, 40, 50};

 // Akses elemen berdasarkan indeks
 System.out.println(angka[0]); // Output: 10
 System.out.println(angka[2]); // Output: 30

 // Tampilkan semua elemen
 for (int i = 0; i < angka.length; i++) {
 System.out.println("Indeks " + i + " = " + angka[i]);
 }
 }
}

public class ContohLooping {
 public static void main(String[] args) {

 // For loop: cetak angka 1 sampai 5
 for (int i = 1; i <= 5; i++) {
 System.out.println("For: " + i);
 }

 // While loop
 int j = 1;
 while (j <= 3) {
 System.out.println("While: " + j);
 j++;
 }

 // Do-while loop
 int k = 1;
 do {
 System.out.println("Do-While: " + k);
 k++;
 } while (k <= 3);
 }
}

public class Main {
 static void sapaUser(String nama) {
 System.out.println("Halo, " + nama);
 }

 public static void main(String[] args) {
 sapaUser("Irfan");
 }
}

public class Main {
 public static void main(String[] args) {
 int angka = 10;
 double desimal = 5.99;
 char huruf = 'A';
 boolean status = true;
 String teks = "Java";
 }
}

class Mobil {
 String merk;
 Mobil(String m) {
 merk = m;
 }

 public static void main(String[] args) {
 Mobil mku = new Mobil("Toyota");
 }
}

interface Hewan {
 void suara();
}

class Kucing implements Hewan {
 public void suara() {
 System.out.println("Meow");
 }
}
